mapper.select:
WITH RECURSIVE pool_tree AS ( SELECT id ,parent_id ,pool_name ,open_day_adjust ,CAST(pool_name AS CHAR(2000)) AS pool_full_name FROM ip_investment_pool WHERE is_deleted = 0 AND parent_id IS NULL UNION ALL SELECT child.id ,child.parent_id ,child.pool_name ,child.open_day_adjust ,CONCAT(parent.pool_full_name, '/', child.pool_name) AS pool_full_name FROM ip_investment_pool child INNER JOIN pool_tree parent ON parent.id = child.parent_id WHERE child.is_deleted = 0 ) SELECT d.id ,d.pool_id ,p.pool_name ,p.pool_full_name ,p.open_day_adjust ,d.begin_date ,d.end_date ,d.description ,d.crte_time ,d.updt_time FROM ip_pool_open_day d LEFT JOIN pool_tree p ON p.id = d.pool_id
AND d.is_deleted = 0
AND d.pool_id = #{poolId}
AND d.begin_date >= #{beginDateFrom}
AND d.end_date <= #{endDateTo}
AND d.description LIKE CONCAT('%', #{description}, '%')
ORDER BY d.begin_date DESC ,d.id DESC

mapper.update:
UPDATE ip_pool_open_day
SET pool_id = #{poolId}
   ,begin_date = #{beginDate}
   ,end_date = #{endDate}
   ,description = #{description}
   ,updt_time = #{updtTime}
WHERE id = #{id}
  AND is_deleted = 0

UPDATE ip_pool_open_day
SET is_deleted = #{isDeleted}
   ,updt_time = #{updtTime}
WHERE id = #{id}
  AND is_deleted = 0
